const raw = $input.first().json.text || '';
let parsed;
try {
  // Extract JSON block — handles markdown code fences or plain JSON
  const match = raw.match(/\{[\s\S]*\}/);
  if (!match) throw new Error('No JSON block found in scorer output');
  parsed = JSON.parse(match[0]);
} catch(e) {
  // Return safe fallback so pipeline doesn't crash
  return [{ json: {
    scores: {},
    score_global: 0,
    parse_error: e.message,
    raw_truncated: raw.slice(0, 200)
  }}];
}

const scores = parsed.scores || {};
const values = Object.values(scores).filter(v => typeof v?.score === 'number');
const score_global = values.length
  ? Math.round((values.reduce((s, v) => s + v.score, 0) / values.length) * 10) / 10
  : 0;

const ctx = $('Execute Workflow Trigger').first().json;
return [{ json: {
  scores,
  score_global,
  p1: ctx.p1 || null,
  metrics: ctx.metrics || null,
  company: ctx.company || null
}}];
